'use client';

import { useEffect, useMemo, useState } from 'react';

type WhatsAppWidgetProps = {
  phoneNumber: string;
  defaultMessage?: string;
  label?: string;
};

/**
 * Floating WhatsApp chat launcher that opens a new conversation with a pre-filled message.
 */
export function WhatsAppWidget({
  phoneNumber,
  defaultMessage = 'Hi! I would love to learn more about working with Moverse.',
  label = 'Chat with us',
}: WhatsAppWidgetProps) {
  const [isHovered, setIsHovered] = useState(false);
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    // Mount diagnostics
    // eslint-disable-next-line no-console
    console.log('[WhatsAppWidget] mounted', {
      phoneNumber,
      defaultMessageLength: defaultMessage?.length,
      label,
    });

    return () => {
      // eslint-disable-next-line no-console
      console.log('[WhatsAppWidget] unmounted');
    };
  }, [phoneNumber, defaultMessage, label]);

  const normalizedPhoneNumber = useMemo(
    () => phoneNumber.replace(/\D/g, ''),
    [phoneNumber],
  );

  const prefilledMessage = useMemo(
    () => encodeURIComponent(defaultMessage.trim()),
    [defaultMessage],
  );

  const handleClick = () => {
    if (!normalizedPhoneNumber) {
      console.error('[WhatsAppWidget] Missing phone number.');
      return;
    }
    setIsOpen((v) => !v);
  };

  const openWebChat = () => {
    const whatsappWebUrl = `https://wa.me/${normalizedPhoneNumber}?text=${prefilledMessage}`;
    // eslint-disable-next-line no-console
    console.log('[WhatsAppWidget] opening Web URL', { whatsappWebUrl });
    window.open(whatsappWebUrl, '_blank', 'noopener,noreferrer');
  };

  const openDesktopApp = () => {
    // This attempts to open the desktop app if installed.
    const whatsappAppUrl = `whatsapp://send?phone=${normalizedPhoneNumber}&text=${prefilledMessage}`;
    // eslint-disable-next-line no-console
    console.log('[WhatsAppWidget] opening Desktop URL', { whatsappAppUrl });
    window.open(whatsappAppUrl, '_blank');
  };

  return (
    <div
      className="pointer-events-none fixed bottom-6 right-6 z-50 flex flex-col items-end gap-3"
      aria-live="polite"
      // eslint-disable-next-line no-console
      onClickCapture={() => console.log('[WhatsAppWidget] container clicked')}
    >
      {/* Popout panel */}
      {isOpen && (
        <div
          className="pointer-events-auto mb-2 w-[320px] max-w-[90vw] overflow-hidden rounded-2xl bg-white text-slate-900 shadow-2xl ring-1 ring-slate-200"
          role="dialog"
          aria-modal="false"
          aria-label="WhatsApp chat options"
        >
          <div className="flex items-center justify-between bg-slate-50 px-4 py-3">
            <div className="flex items-center gap-2">
              <div className="flex h-8 w-8 items-center justify-center rounded-full bg-[#25D366] text-white">
                <svg
                  className="h-5 w-5"
                  viewBox="0 0 24 24"
                  fill="currentColor"
                  xmlns="http://www.w3.org/2000/svg"
                  aria-hidden="true"
                >
                  <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z" />
                </svg>
              </div>
              <div>
                <p className="text-sm font-semibold">Chat with Moverse</p>
                <p className="text-xs text-slate-500">Typically replies in minutes</p>
              </div>
            </div>
            <button
              type="button"
              onClick={() => setIsOpen(false)}
              className="rounded-md p-1 text-slate-500 hover:bg-slate-100 hover:text-slate-700 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-slate-300"
              aria-label="Close chat options"
            >
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="h-5 w-5"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
            </button>
          </div>

          <div className="space-y-3 px-4 py-3">
            <div className="rounded-lg bg-slate-100 px-3 py-2 text-sm text-slate-700">
              {decodeURIComponent(prefilledMessage)}
            </div>
            <p className="text-sm text-slate-600">How would you like to continue?</p>

            <div className="flex flex-col gap-2">
              <button
                type="button"
                onClick={openDesktopApp}
                className="inline-flex w-full items-center justify-center gap-2 rounded-md bg-slate-900 px-4 py-2 text-sm font-medium text-white shadow-sm transition hover:bg-slate-800 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-slate-300"
              >
                Open desktop app
              </button>
              <button
                type="button"
                onClick={openWebChat}
                className="inline-flex w-full items-center justify-center gap-2 rounded-md bg-[#25D366] px-4 py-2 text-sm font-medium text-white shadow-sm transition hover:bg-[#21bf5c] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#25D366]/40"
              >
                Continue on web
              </button>
              <button
                type="button"
                onClick={() => setIsOpen(false)}
                className="inline-flex w-full items-center justify-center gap-2 rounded-md border border-slate-200 bg-white px-4 py-2 text-sm font-medium text-slate-700 shadow-sm transition hover:bg-slate-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-slate-200"
              >
                Not now
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Label tooltip - positioned above the button */}
      <div
        className={`pointer-events-auto origin-bottom-right transform transition-all duration-300 ease-out ${
          isHovered ? 'opacity-100 translate-y-0 scale-100' : 'translate-y-2 opacity-0 scale-95'
        }`}
      >
        <span className="inline-flex max-w-xs items-center rounded-full bg-white/95 px-4 py-2 text-sm font-medium text-slate-900 shadow-lg ring-1 ring-slate-200 backdrop-blur-sm">
          {label}
        </span>
      </div>

      {/* WhatsApp Button with official icon */}
      <button
        type="button"
        onClick={handleClick}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
        onFocus={() => setIsHovered(true)}
        onBlur={() => setIsHovered(false)}
        className="pointer-events-auto flex h-16 w-16 items-center justify-center rounded-full bg-[#25D366] text-white shadow-2xl transition-all duration-300 ease-out hover:scale-110 hover:shadow-[0_8px_30px_rgb(37,211,102,0.4)] focus-visible:outline-none focus-visible:ring-4 focus-visible:ring-[#25D366]/50 active:scale-95"
        aria-label="Open WhatsApp chat"
      >
        {/* Official WhatsApp Icon SVG */}
        <svg
          className="h-8 w-8"
          viewBox="0 0 24 24"
          fill="currentColor"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
        >
          <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z" />
        </svg>
      </button>
    </div>
  );
}

export default WhatsAppWidget;